          sessionId: `test_${i}`,
          timestamp: Date.now() + i * 1000,
          identity: 'CAIRΘ',
          deposits: [{ type: 'knowledge', identifier: `k${i}`, size: 100, permanence: 0.8 }],
          sedimentType: 'knowledge',
          brackishness: 0.5
        });
